import java.util.Arrays;

public class Solution {
    public static long solve(long[] nums) {
        int n = nums.length;
        long[] abs = new long[n];
        for (int i = 0; i < n; i++) {
            abs[i] = Math.abs(nums[i]);
        }
        Arrays.sort(abs);
        long count = 0;
        for (int i = 0; i < n - 1; i++) {
            long target = 2 * abs[i];
            int low = i + 1;
            int high = n - 1;
            int res = -1;
            while (low <= high) {
                int mid = (low + high) / 2;
                if (abs[mid] <= target) {
                    res = mid;
                    low = mid + 1;
                } else {
                    high = mid - 1;
                }
            }
            if (res != -1) {
                count += (res - i);
            }
        }
        return count;
    }
}
